(window.webpackJsonp=window.webpackJsonp||[]).push([[329],{956:function(n,t){n.exports="\x3c!-- \ntitle: 07-ReactRouter\nsort: \n--\x3e \n\n> 使用路由进行跳转\n>\n> `yarn add react-route-dom`\n\n### Route.js\n\n```js\n// import { BrowserRouter as Router, Route, Switch } from 'react-router-dom'\n// 哈希路由，自动加#, 路由, 匹配开关, 重定向\nimport { HashRouter as Router, Route, Switch, Redirect } from 'react-router-dom'\nimport App from './pages/app'\nimport Login from './pages/login'\nimport Home from './pages/home'\nimport Detail from './pages/detail'\nimport NoMatch from './pages/404'\n\nexport default function IRouter() {\n  return <Router>\n    <Switch>\n      <Route exact path=\"/\" component={App}></Route>\n      <Route path=\"/login\" component={Login}></Route>\n      <Route path=\"/home\" component={Home}>\n        <Redirect to='/login'></Redirect>\n      </Route>\n      <Route path=\"/detail/:id\" component={Detail}></Route>\n      <Route path=\"*\" component={NoMatch}></Route>\n    </Switch>\n  </Router>\n}\n```\n\n### App.js\n\n```js\nimport React from 'react'\nimport { Link } from 'react-router-dom'\n// import { Button } from 'antd'\n// import 'antd/dist/antd.css'\nimport './app.scss'\n\n// 无状态\nexport default function App() {\n    return <div class=\"container\">\n        <h1>React Route Test</h1>\n        <Link to=\"login\">To Login</Link>\n        <br />\n        <Link to=\"home\">To Home</Link>\n        <br />\n    </div>\n}\n\n// 有状态\n// export default class App extends React.Component {\n\n//   handleJump = () =>{\n//     this.props.history.push('/login');\n//   }\n\n//   render() {\n//     return <div class=\"container\">\n//       <h1>React Route Test</h1>\n//       <Link to=\"login\">To Login</Link>\n//       <br />\n//       <Link to=\"home\">To Home</Link>\n//       <br />\n//       <Button onClick={this.handleJump}>Click Me</Button>\n//     </div>\n//   }\n// }\n```\n\n## 动态路由\n\n> 动态交互的地方需要动态路由\n\n```js\n<Route path=\"/detail/:id\" component={Detail}></Route>\n\n// /detail/:id\nimport React from 'react'\nimport { Link } from 'react-router-dom'\nimport './app.scss'\n\nexport default function Detail() {\n    return <div class=\"container\">\n        <h1>React Route Detail Test</h1>\n    </div>\n}\n```\n\n## Hooks\n\n> useState, useEffect\n\n```js\nimport React, { useState,useEffect } from 'react'\nimport { Button } from 'antd'\nimport 'antd/dist/antd.css'\nimport './app.scss'\n\n// 无state\nexport default function App() {\n\n  // 返回数组\n  const [count, setCount] = useState(10);\n\n  useEffect(()=>{\n    console.log('useEffect Running');\n    setCount(100)\n  },[])\n\n  return <div class=\"container\">\n    <p>\n      Value of Count: {count}\n    </p>\n    <Button onClick={()=>setCount(count+1)}>Add</Button>\n  </div>\n}\n\n```\n\n### RouteHooks\n\n> useParams, useHistory\n>\n> 获取动态路由的params，跳转\n\n```js\nimport React from 'react'\nimport { useParams, useHistory } from 'react-router-dom'\nimport { Button } from 'antd'\nimport 'antd/dist/antd.css'\nimport './app.scss'\n\nexport default function Detail() {\n  const params = useParams();\n  const history = useHistory();\n  return <div className=\"container\">\n    <h1>React Route Detail Test</h1>\n    <p>Value of ID: {params.id}</p>\n    <Button onClick={()=>\n      history.push('/')\n      }>Return</Button>\n  </div>\n}\n\n/*\nexport default class App extends React.Component {\n\n  handleJump = () => {\n    this.props.history.push('/login');\n  }\n\n  render() {\n    return <div class=\"container\">\n      <h1>React Route Detail Test</h1>\n      <p>Value of ID: {this.props.match.params.id}</p>\n    </div>\n  }\n}\n*/\n```\n\n"}}]);